# Configure AWS provider for account 696505809372 and region eu-north-1.
# Credentials: default chain (AWS_ACCESS_KEY_ID/AWS_SECRET_ACCESS_KEY, or ~/.aws/credentials [default]).
# If you use a named profile, add: profile = "your-profile-name" (do not use account ID as profile name).

terraform {
  required_version = ">= 1.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.0"
    }
  }
}

provider "aws" {
  region = "eu-north-1"
}

# SSM block public document sharing - Action: e8be6f05-0e5e-4bdc-818e-f551cd62ccb5
resource "aws_ssm_service_setting" "security_autopilot" {
  setting_id    = "arn:aws:ssm:eu-north-1:696505809372:servicesetting/ssm/documents/console/public-sharing-permission"
  setting_value = "Disable"
}
